then.script:
    // -------------------------------
    // Get variables from message context
    // -------------------------------
    var claimId = mc.getProperty("claimId") || "N/A";
    var policyId = mc.getProperty("policyId") || "N/A";
    var claimIntimationDate = mc.getProperty("claimIntimationDate") || new Date().toISOString();

    // -------------------------------
    // Format dates
    // -------------------------------
    var now = new Date();
    var options = { month: 'long', day: '2-digit', year: 'numeric', hour:'2-digit', minute:'2-digit', hour12:true };
    var formattedNow = now.toLocaleString('en-US', options);

    var intimationDate = new Date(claimIntimationDate);
    var formattedIntimationDate = intimationDate.toLocaleString('en-US', options);

    // -------------------------------
    // Build email subject
    // -------------------------------
    var emailSubject = "Claim Update for Claim " + claimId;
    mc.setProperty("Email_Subject", emailSubject);

    // -------------------------------
    // Build email HTML body
    // -------------------------------
    var emailBody = '<!doctype html>\
<html lang="en">\
<head>\
  <meta charset="utf-8">\
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\
  <style>\
    body { margin:0; padding:0; font-family:Arial, Helvetica, sans-serif; background:#f4f6f8; color:#333; }\
    .container { max-width:700px; margin:20px auto; background:#fff; border-radius:6px; box-shadow:0 2px 6px rgba(0,0,0,0.15); }\
    .header { background:#2c3e50; padding:24px; text-align:center; color:#fff; font-size:26px; font-weight:bold; }\
    .body { padding:30px; font-size:15px; line-height:1.6; }\
    .section-title { font-size:20px; font-weight:bold; margin-bottom:20px; text-align:center; }\
    .footer { padding:20px; text-align:center; font-size:12px; color:#9aa7bf; }\
  </style>\
</head>\
<body>\
  <div class="container">\
    <div class="header">Claim Update for Claim ' + claimId + '</div>\
    <div class="body">\
      <p>' + formattedNow + '</p>\
      <p>Dear User,</p>\
      <p>We would like to inform you that the review of your Personal Auto Insurance claim submitted on ' + formattedIntimationDate + ' has been completed.</p>\
      <p>For security and privacy reasons, detailed information regarding the outcome of your claim is available only through the Exasure Insurance Integration Cloud portal.</p>\
      <p>Please log in to your account to view the full details, including next steps and any actions required from your side.</p>\
      <div style="margin:25px 0; text-align:center;">\
        <a href="http://localhost:5173/home" style="background:#2c3e50; color:#ffffff; padding:12px 22px; text-decoration:none; font-size:15px; font-weight:bold; border-radius:6px; display:inline-block;">View Claim Details</a>\
      </div>\
      <p>If you have questions or need assistance accessing the portal, please contact our Claims Support team at exavaluinsuranceaccelarator@gmail.com.</p>\
      <p>Sincerely,<br>\
      <strong>Exasure IIC</strong><br>\
      Claims & Customer Support</p>\
    </div>\
    <div class="footer">\
      Exasure | http://localhost:5173/home<br>\
      This is an automated message. Please do not reply.\
    </div>\
  </div>\
</body>\
</html>';

    // -------------------------------
    // Set the email body property
    // -------------------------------
    mc.setProperty("Email_Body", emailBody);

    // -------------------------------
    // Logging for debugging
    // -------------------------------
    mc.getServiceLog().info("Email_Async_Start = Starting async email");
    mc.getServiceLog().info("ClaimId = " + claimId);
    mc.getServiceLog().info("PolicyId = " + policyId);
    mc.getServiceLog().info("Email_Subject = " + emailSubject);
    mc.getServiceLog().info("Email_Body (first 200 chars) = " + emailBody.substring(0,200) + "...");
    mc.getServiceLog().info("Email_Async_End = Email properties prepared for sending");
